-- V5__seed_data.sql
-- Importação inicial dos dados da planilha "Conexões_Orion"
--
-- DEPARA (mapeamento de colunas):
--   PDF "Serventia"        -> clients.name
--   PDF "ID"               -> connections.id_remote_connection  (espaços removidos)
--   PDF "Senha"            -> connections.password_remote_connection
--   PDF "Usuário Windows"  -> connections.user_machine
--   PDF "Senha Windows"    -> connections.password_machine
--   user_db / password_db  -> NULL (coluna "Obs." do PDF - dados incompletos para mapeamento automatizado)
--
-- TIPO DE CONEXÃO (cores no PDF original):
--   Azul escuro  = TEAMVIEWER  -> 1ª linha de cada cartório
--   Azul claro   = ANYVIEWER   -> 2ª linha de cada cartório
--   Vermelho     = ANYDESK     -> 3ª linha de cada cartório
--   Amarelo      = HOPTODESK   -> linhas que apareciam em amarelo no PDF
-- Para cartórios com 1 linha, atribuído TEAMVIEWER por padrão.
-- IMPORTANTE: Revisar e corrigir os tipos via frontend após a importação.
--
-- Todos os cartórios recebem versão 05.82.01.

-- ============================================================
-- 1. VERSÃO
-- ============================================================
INSERT INTO versions (id, date_release, number_version, changelog, created_at, activate)
VALUES (
    '10000000-0000-0000-0000-000000000001',
    CURRENT_DATE,
    '05.82.01',
    'Versão base - importação inicial da planilha de conexões Orion',
    CURRENT_TIMESTAMP,
    true
);

